function(){
var targetX = 6,
	targetY = 7;

var a = new Array(
	[5, 4], [4, 4], [3, 4], [7, 4], [8, 4], [9, 4],
	[4, 2], [3, 2], [2, 2], [8, 2], [9, 2], [10, 2], [6, 1]
);

function getSteps(x, y, tx, ty) {
	let steps = [];

	// 水平移动：x → tx
	let dx = tx - x;
	if (dx !== 0) {
		let dir = dx > 0 ? "right" : "left";
		steps.push(`${dir}:${Math.abs(dx)}`);
	}

	// 竖直移动：y → ty
	let dy = ty - y;
	if (dy !== 0) {
		let dir = dy > 0 ? "down" : "up";
		steps.push(`${dir}:${Math.abs(dy)}`);
	}

	return steps;
}
let todo = [];

for (var i = 0; i <= 12; i++) {
	var x = a[i][0],
		y = a[i][1];

	if (core.getBlockId(x, y) !== null) {
		// 生成 steps
		var steps = getSteps(x, y, targetX, targetY);
		// 移动动画
		core.push(todo, [
			{ "type": "sleep", "time": 300 },
			{
				"type": "move",
				"loc": [x, y],
				"time": 300,
				"keep": true,
				"steps": steps
			},
			{
				"type": "battle",
				"loc": [targetX, targetY]
			}
		]);
	}
	if (i === 2) core.push(todo, '\t[yellowKnight]哼，没关系，士兵们给我上！');
	else if (i === 5) core.push(todo, '\t[yellowKnight]真正的战斗才刚开始，让我们继续，双手剑士给我上！');
	else if (i === 8) core.push(todo, '\t[yellowKnight]哼，你们这战怎么打得？骑士们给我冲！');
	else if (i === 11) core.push(todo, '\t[yellowKnight]你怎会击败我所有的手下？我和你誓不两立我决不认输。（骑士队长失去了理智）');
	else if (i === 12) {
		core.push(todo, {
			"type": "setBlock",
			"number": "upFloor",
			"loc": [
				[6, 1]
			]
		});
		core.push(todo, {
			"type": "setBlock",
			"number": "yellowKnight",
			"loc": [
				[targetX, targetY]
			]
		});
		core.push(todo, "\t[yellowKnight]这次先饶了你，下次碰到我会和你正式的决斗，你最好投降。（骑士队长逃走了）");
		core.push(todo, {
			"type": "move",
			"loc": [targetX, targetY],
			"time": 100,
			"keep": false,
			"steps": ['up:6']
		});
	}

}
core.insertAction(todo);
}

