function(){
const keyItems = ['yellowKey', 'blueKey', 'redKey'];

function countNonKeyItems(data) {
	let t = 0;
	Object.values(data.constants).forEach(v => t += v);
	for (const [k, v] of Object.entries(data.tools)) {
		if (!keyItems.includes(k)) t += v;
	}
	Object.values(data.equips).forEach(v => t += v);
	return t;
}
core.status.hero.hp = countNonKeyItems(core.status.hero.items) - 1;
}
